const JSEncrypt = require("jsencrypt");
const { webcrypto } = require("crypto");
const crypto = webcrypto;

function rsaDecrypt(base64Key) {
  const rsaPublicKey =
    "-----BEGIN PRIVATE KEY-----\n        MIICdwIBADANBgkqhkiG9w0BAQEFAASCAmEwggJdAgEAAoGBAOhM0pNOfGeiBr+t\n    nunphCHReY3RiS4Fuc2nD3cbjKNdLezeViGmsZwHsb2SVUb6rpPHyX0+3xjXYn//\n    n39/Q8uPjWRA332TtN8MDEkSR2HMbn8ufRRt2TnlfsFDFTgBywSP7cwd0CiEdvBX\n    5w8Jifc9VbedwbeplBWyDeLLqjRjAgMBAAECgYB4es+EAuLWxNwHMb8Hxkr3VzNZ\n    8GDbc7DIDmsg9TLdz4fwH+hAD7pyGDOBBJIh/AXrM2U3BhKjSaIWjLdmYtT/kzg8\n    BxQDr9YoO7u2jvTcEE+/6p2YugYX/ngpinawFJqyM+N7Or8yRABaw6Aq8VuKtv6p980Y2BBVVYn+/KorYQJBAP+9lu8iolzKRzJrFt/rosdWkOpNg5ujcSCwbxhYnYC0\n    UY85sPLsMvnLgegkpO8jocSAt586BmcsA+Q9o97qVCkCQQDoiSVegtOvG3U0mNlN\n    rCVpPEL22s9Kkwps3ZCdTl3VtUtNiyfhE8rbw/qOGti3VxMCRhpKi9hTIgeq13UG\n    67WrAkEA/WQ1c5XGd9f4eU1AKffInmf4SB8rgn+L7I7EVMQgstB3a0kHOXqs+3IX\n    shL01PliJFhBF+QfSgSDipdEke9uGQJBAOcw46xxmhDw1bizdulYi+Fy/oj7xzi3\n    tJfEObGMZpLBKtsvzThkOz4APS3n1yuBMO8Dz8PqAeu1W7YpfLqiwv0CQF68N244\n    dFebDSoZLl1hbCExpbtC7SDBpYxlIVNVqwN7ymr+Z0rIcAMVv5Ldp/bJEWaXJs9C\n    0sPCBpjDnyK9Z04=\n        -----END PRIVATE KEY-----";
  crypt.setPublicKey(rsaPublicKey);
  const res = crypt.decrypt(base64Key);
  return res;
}

const crypt = new JSEncrypt();

const base64Key =
  "LcKjNnjn9a2P2Y3zNWcO823o3uqJL1LmFBkpzxTUJ0xAjsXK8HPwmhTT+qyRaTAez6AQd4L/4vSVBI4ChN7KiLbW1Robpf5XbF+ssQowfHxCcXZ/3SqcQQRD1vzdbW0d5dnJo703TzcX3Dhsa4PTeSHLYp+MnlzAmyAta3Z07o0=";
const cipherText =
  "";

const aesKey = rsaDecrypt(base64Key);

/**
 * AES-CTR 解密工具函数
 * @param {string} key - 解密密钥（字符串）
 * @param {string} cipherText - Base64 编码的加密文本
 * @returns {Promise<string>} 解密后的明文
 */
async function aesCtrDecrypt(key, cipherText) {
  try {
    // 1. 将密钥字符串转换为 Uint8Array 格式
    const keyBytes = new TextEncoder().encode(key);

    // 2. 导入密钥（AES-CTR 算法）
    const cryptoKey = await crypto.subtle.importKey(
      "raw",
      keyBytes,
      { name: "AES-CTR" },
      false, // 不可导出
      ["encrypt", "decrypt"],
    );

    // 3. 解码 Base64 加密文本，分离计数器和密文
    const encryptedData = Uint8Array.from(atob(cipherText), (char) =>
      char.charCodeAt(0),
    );
    const counter = encryptedData.slice(0, 16); // 前16字节是计数器
    const cipherData = encryptedData.slice(16); // 剩余部分是密文

    // 4. 执行解密
    const decryptedBuffer = await crypto.subtle.decrypt(
      {
        name: "AES-CTR",
        counter: counter,
        length: 128,
      },
      cryptoKey,
      cipherData,
    );

    // 5. 将解密后的 ArrayBuffer 转换为字符串
    const decryptedText = new TextDecoder().decode(decryptedBuffer);
    return decryptedText;
  } catch (error) {
    console.error("AES-CTR 解密失败：", error);
    throw new Error(`解密出错：${error.message}`);
  }
}

async function main() {
  // 关键：调用函数 + await 等待结果
  const decryptedResult = await aesCtrDecrypt(aesKey, cipherText);

  // 在这里输出真正的解密结果
  console.log("✅ 解密结果：", decryptedResult);
}

main()

